SELECT 
  FROM emp.tn_emp_co2_detail d
 WHERE d.emp_plan_id  = #{empPlanId}
   AND d.mntr_mthd_cd = #{mntrMthdCd}
   AND NOW() BETWEEN d.use_bgng_dt AND d.use_end_dt

SELECT COUNT(*)
  FROM emp.tn_emp_co2_detail
 WHERE emp_plan_id  = #{empPlanId}
   AND mntr_mthd_cd = #{mntrMthdCd}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

mapper.update:
UPDATE emp.tn_emp_co2_detail
   SET msr_tming_desc  = #{msrTmingDesc},
       msr_device_desc = #{msrDeviceDesc},
       msr_proc_desc   = #{msrProcDesc},
       fuel_dnsty_desc = #{fuelDnstyDesc},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{lastChgUserId}
 WHERE emp_plan_id  = #{empPlanId}
   AND mntr_mthd_cd = #{mntrMthdCd}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE emp.tn_emp_co2_detail
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE emp_plan_id  = #{empPlanId}
   AND mntr_mthd_cd = #{mntrMthdCd}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
